mapper.sql:
where tenant_id = #{tenantId} and logical_object_id = #{logicalObjectId}

    and (lower(physical_object_code) like concat('%', lower(#{keyword}), '%')
      or lower(physical_object_name) like concat('%', lower(#{keyword}), '%'))

and status = #{status}

mapper.select:
select * from fp_logical_object_instance

order by last_seen_at desc
limit #{pageSize} offset #{offset}

select * from fp_logical_object_instance
where tenant_id = #{tenantId}
  and logical_object_id = #{logicalObjectId}
  and physical_object_type = #{physicalObjectType}
  and physical_object_code = #{physicalObjectCode}
